installer-gui-script.script:

function check_obs_present() {
    system.log("check_obs_present: START");

    const MIN_OBS_VERSION = "31.1.0";

    system.log("check_obs_present: MIN_OBS_VERSION: " + MIN_OBS_VERSION);

    system.log("check_obs_present: my.target: " + JSON.stringify(my.target));

    let mountPointPrefix = (my.target || {}).mountPoint || "/";
    if (mountPointPrefix[mountPointPrefix.length - 1] !== "/") {
        mountPointPrefix += "/";
    }

    system.log("check_obs_present: mountPointPrefix: " + mountPointPrefix);

    const obsPath = mountPointPrefix + "Applications/OBS.app";

    system.log("check_obs_present: obsPath: " + obsPath);

    const obsInfo = system.files.bundleAtPath(obsPath);

    system.log("check_obs_present: obsInfo: " + JSON.stringify(obsInfo));

    if (!obsInfo) {
        system.log("check_obs_present: obsInfo is null");

        my.result.title = "OBS Studio not found.";
        my.result.message = "Please install the latest version of OBS Studio from https://obsproject.com before installing SE.Live.";
        my.result.type = "Fatal";

        return true;
    }

    const obsVersion = obsInfo.CFBundleShortVersionString || '0.0.0';

    system.log("check_obs_present: obsVersion: " + obsVersion);

    if (system.compareVersions(obsVersion, MIN_OBS_VERSION) < 0) {
        system.log("check_obs_present: obsVersion < MIN_OBS_VERSION");

        my.result.title = "OBS Studio is too old.";
        my.result.message = "Please install the latest version of OBS Studio from https://obsproject.com before installing SE.Live.";
        my.result.type = "Fatal";

        return true;
    }

    system.log("check_obs_present: all OK");

    return true;
}
